CREATE MATERIALIZED VIEW "public"."mv_helpdesk_agent_stats" AS (select "workspace_id", "id", "name", "status", "tickets_resolved", "tickets_assigned", "average_response_time", "satisfaction_score" from "helpdesk_agents" where "helpdesk_agents"."deleted_at" IS NULL) WITH NO DATA;--> statement-breakpoint
CREATE MATERIALIZED VIEW "public"."mv_helpdesk_conversations_daily" AS (select "workspace_id", DATE_TRUNC('day', "created_at") as "period", "status", "channel", COUNT(*) as "conversation_count", AVG("message_count") as "avg_messages" from "helpdesk_conversations" where "helpdesk_conversations"."deleted_at" IS NULL group by "helpdesk_conversations"."workspace_id", DATE_TRUNC('day', "helpdesk_conversations"."created_at"), "helpdesk_conversations"."status", "helpdesk_conversations"."channel") WITH NO DATA;--> statement-breakpoint
CREATE MATERIALIZED VIEW "public"."mv_helpdesk_satisfaction_daily" AS (select "workspace_id", DATE_TRUNC('day', "sent_at") as "period", COUNT(*) as "survey_count", COUNT(*) FILTER (WHERE "status" = 'completed') as "completed_count", AVG("rating") FILTER (WHERE "status" = 'completed') as "avg_rating", COUNT(*) FILTER (WHERE "rating" >= 9) as "promoters", COUNT(*) FILTER (WHERE "rating" <= 6) as "detractors" from "helpdesk_satisfaction_surveys" where "helpdesk_satisfaction_surveys"."deleted_at" IS NULL group by "helpdesk_satisfaction_surveys"."workspace_id", DATE_TRUNC('day', "helpdesk_satisfaction_surveys"."sent_at")) WITH NO DATA;--> statement-breakpoint
CREATE MATERIALIZED VIEW "public"."mv_helpdesk_tickets_daily" AS (select "workspace_id", DATE_TRUNC('day', "created_at") as "period", "status", "priority", "channel", COUNT(*) as "ticket_count", COUNT(*) FILTER (WHERE "is_escalated" = true) as "escalated_count", AVG("response_time") FILTER (WHERE "response_time" IS NOT NULL) as "avg_response_time", AVG("resolution_time") FILTER (WHERE "resolution_time" IS NOT NULL) as "avg_resolution_time" from "helpdesk_tickets" where "helpdesk_tickets"."deleted_at" IS NULL group by "helpdesk_tickets"."workspace_id", DATE_TRUNC('day', "helpdesk_tickets"."created_at"), "helpdesk_tickets"."status", "helpdesk_tickets"."priority", "helpdesk_tickets"."channel") WITH NO DATA;